/*
 * nic_mla_format.h  —  NIC-MLA: shared format definition (header-only, v1.0)
 *
 * Common to both C libraries:
 *   • nic_mla_write.{h,c}  — write-only, for ATmega / small Arduino
 *   • nic_mla.{h,c}        — complete, for ARM Arduino / PC (Python port)
 *
 * Everything is serialized EXPLICITLY byte by byte in little-endian — no
 * reliance on the C struct layout. The binary format is identical across
 * AVR / ARM / PC and the Python reference.
 *
 * A deliberately DUMB container:
 *   • LOG record = 16 B, the WHOLE record covered by the CRC.
 *   • Abandon a record by overwriting it with zeros (its CRC then fails).
 *   • station is a 1-byte INDEX into the prefix station table; C never
 *     interprets it — translation is the host glue's job.
 *   • The prefix carries two opaque-to-MLA tables (schema + station), written
 *     verbatim from above; it grows in 512 B sectors (up to 255) to fit them.
 *   • No checkpoints, no on-disk index/search tree.
 *
 * MIT  |  ★ Viva La Resistánce ★
 */
#ifndef NIC_MLA_FORMAT_H
#define NIC_MLA_FORMAT_H

#include <stdint.h>
#include <string.h>

/* ── Format constants ───────────────────────────────────────────────────── */
#define MLA_VERSION         1
#define MLA_PREFIX_SIZE     512u
#define MLA_MAX_PREFIX_SEC  255u     /* hard limit: 255 sectors (~127 KB) — theoretical */
#define MLA_REC_PREFIX_SEC  16u      /* recommended ceiling: 16 sectors (8 KB) */
#define MLA_LOG_REC_SIZE    16u
#define MLA_PFX_HDR_SIZE    34u      /* structured part of the prefix (no padding) */

#define MLA_DATA_MAGIC0     0xABu
#define MLA_DATA_MAGIC1     0xCDu

/* flags (bits 0-1 = CRC mode) */
#define MLA_CRC_NONE        0
#define MLA_CRC_DATA        1
#define MLA_CRC_FULL        2

/* rec_type: low nibble = encoding, high nibble = class */
#define MLA_ENC_RAW         0x0u
#define MLA_ENC_DELTA       0x1u
#define MLA_ENC_KEYFRAME    0x2u
#define MLA_ENC_TEXT        0x3u
#define MLA_CLASS_MEASURE   0x00u
#define MLA_CLASS_EVENT     0x10u
#define MLA_CLASS_CONFIG    0x20u

/* return codes */
#define MLA_OK              0
#define MLA_E_IO            (-1)
#define MLA_E_FULL          (-2)
#define MLA_E_BADFMT        (-3)
#define MLA_E_RANGE         (-4)
#define MLA_E_NOTFOUND      (-5)
#define MLA_E_NOSUP         (-6)

/* ── Self-describing tables (carried in the prefix free space) ───────────── */
/* Both tables sit at [MLA_SCHEMA_OFF .. ) inside the prefix, covered by the
 * prefix CRC. Generated by tools/mla_schema.py and written verbatim at
 * format() time. MLA does not interpret their contents.
 *
 *   SCHEMA table:  [0]=MLA_SCHEMA_VER  [1]=n_log  [2]=n_data  then
 *                  (n_log+n_data) × 14 B field descriptors
 *                  (width, unit, exp10, flags, offset[i16], name[8 B]).
 *   STATION table: [0]=MLA_STATION_VER [1]=n  then n × 6 raw bytes
 *                  (index 1..n → record; the 6 bytes' meaning is the glue's).
 */
#define MLA_SCHEMA_OFF    MLA_PFX_HDR_SIZE             /* 34 */
#define MLA_SCHEMA_VER    1u
#define MLA_FIELD_SIZE    14u                          /* 6 core + 8 name */
#define MLA_STATION_VER   0x53u                        /* tag, distinct from schema ver */
#define MLA_STATION_REC   6u

static inline uint16_t mla_schema_size(uint8_t n_log, uint8_t n_data) {
    return (uint16_t)(3u + MLA_FIELD_SIZE * (uint16_t)(n_log + n_data));
}
static inline uint16_t mla_station_size(uint8_t n) {
    return n ? (uint16_t)(2u + MLA_STATION_REC * (uint16_t)n) : 0u;
}
/* Total prefix size (CRC included) for the given table byte counts, rounded up
 * to whole 512 B sectors. Returns 0 if it would exceed MLA_MAX_PREFIX_SEC. */
static inline uint32_t mla_prefix_size(uint16_t schema_len, uint16_t station_len) {
    uint32_t need = (uint32_t)MLA_SCHEMA_OFF + schema_len + station_len + 2u;
    uint32_t sectors;
    if (need <= MLA_PREFIX_SIZE) return MLA_PREFIX_SIZE;
    sectors = (need + MLA_PREFIX_SIZE - 1u) / MLA_PREFIX_SIZE;
    if (sectors > MLA_MAX_PREFIX_SEC) return 0u;
    return sectors * MLA_PREFIX_SIZE;
}

/* ── HAL — 4 functions, logical offsets (0 .. file_size-1) ───────────────── */
typedef struct {
    int      (*read)(void *ctx, uint32_t off, void *buf, uint16_t n);   /* 0=OK */
    int      (*write)(void *ctx, uint32_t off, const void *buf, uint16_t n);
    void     (*sync)(void *ctx);
    uint32_t (*size)(void *ctx);
    void     *ctx;
} mla_hal_t;

/* ── Little-endian helpers ──────────────────────────────────────────────── */
static inline void mla_put_u16(uint8_t *p, uint16_t v) { p[0]=(uint8_t)v; p[1]=(uint8_t)(v>>8); }
static inline void mla_put_u32(uint8_t *p, uint32_t v) {
    p[0]=(uint8_t)v; p[1]=(uint8_t)(v>>8); p[2]=(uint8_t)(v>>16); p[3]=(uint8_t)(v>>24);
}
static inline uint16_t mla_get_u16(const uint8_t *p) { return (uint16_t)(p[0] | (p[1]<<8)); }
static inline uint32_t mla_get_u32(const uint8_t *p) {
    return (uint32_t)p[0] | ((uint32_t)p[1]<<8) | ((uint32_t)p[2]<<16) | ((uint32_t)p[3]<<24);
}

/* ── CRC-16 / CCITT-FALSE  (poly 0x1021, init 0xFFFF) ───────────────────── */
static inline uint16_t mla_crc16_ex(uint16_t crc, const uint8_t *data, uint16_t len) {
    uint16_t i; uint8_t b;
    for (i = 0; i < len; i++) {
        crc ^= (uint16_t)data[i] << 8;
        for (b = 0; b < 8; b++)
            crc = (crc & 0x8000u) ? (uint16_t)((crc << 1) ^ 0x1021u) : (uint16_t)(crc << 1);
    }
    return crc;
}
static inline uint16_t mla_crc16(const uint8_t *data, uint16_t len) {
    return mla_crc16_ex(0xFFFFu, data, len);
}

/* ── LOG record (16 B) — the WHOLE record is covered by the CRC ─────────── */
typedef struct {
    uint32_t offset;      /* [0]  logical offset of the data block */
    uint32_t timestamp;   /* [4]  Unix seconds */
    uint16_t length;      /* [8]  payload length 1..65535 */
    uint8_t  rec_type;    /* [10] encoding + class */
    uint8_t  kf_back;     /* [11] records back to the owning keyframe (0 = is one) */
    uint8_t  station;     /* [12] index 1..255 into the station table (0 = none) */
    uint8_t  reserved;    /* [13] 0 */
} mla_log_t;

/* Serialize → 16 B (14 B body + CRC16 over [0..13]). */
static inline void mla_log_build(uint8_t out[MLA_LOG_REC_SIZE], const mla_log_t *r) {
    mla_put_u32(out + 0,  r->offset);
    mla_put_u32(out + 4,  r->timestamp);
    mla_put_u16(out + 8,  r->length);
    out[10] = r->rec_type;
    out[11] = r->kf_back;
    out[12] = r->station;
    out[13] = r->reserved;
    mla_put_u16(out + 14, mla_crc16(out, 14));
}

/* Deserialize; returns 1 if the CRC matches (a zeroed/0xFF slot returns 0). */
static inline int mla_log_parse(const uint8_t in[MLA_LOG_REC_SIZE], mla_log_t *r) {
    r->offset    = mla_get_u32(in + 0);
    r->timestamp = mla_get_u32(in + 4);
    r->length    = mla_get_u16(in + 8);
    r->rec_type  = in[10];
    r->kf_back   = in[11];
    r->station   = in[12];
    r->reserved  = in[13];
    return mla_crc16(in, 14) == mla_get_u16(in + 14);
}

static inline uint32_t mla_log_block_end(const mla_log_t *r) {
    return r->offset + 2u + r->length + 2u;
}

/* ── Prefix — structured header [0..33] ─────────────────────────────────── */
typedef struct {
    uint8_t  version;
    uint8_t  cluster_shift;
    uint8_t  log_rec_size;     /* = 16 */
    uint8_t  flags;
    uint32_t file_size;
    uint8_t  container_kind;
    uint16_t file_seq;
    uint8_t  keyframe_intv;
    uint8_t  enc_caps;
    uint32_t data_base;        /* first data byte = prefix size */
    uint32_t region_end;       /* = file_size */
} mla_prefix_t;

/* Fill the structured prefix header (34 B). magic 'M','L','A',0. */
static inline void mla_prefix_build_hdr(uint8_t hdr[MLA_PFX_HDR_SIZE], const mla_prefix_t *p) {
    memset(hdr, 0, MLA_PFX_HDR_SIZE);
    hdr[0]='M'; hdr[1]='L'; hdr[2]='A'; hdr[3]=0;
    hdr[4]=p->version;
    hdr[5]=p->cluster_shift;
    hdr[6]=p->log_rec_size;
    hdr[7]=p->flags;
    mla_put_u32(hdr + 8,  p->file_size);
    /* [12..19] reserved (0) */
    hdr[20]=p->container_kind;
    mla_put_u16(hdr + 21, p->file_seq);
    hdr[23]=p->keyframe_intv;
    hdr[24]=p->enc_caps;
    mla_put_u32(hdr + 25, p->data_base);
    mla_put_u32(hdr + 29, p->region_end);
    /* [33] reserved (0) */
}

/* Parse the structured header; returns 1 if magic+version match. */
static inline int mla_prefix_parse_hdr(const uint8_t hdr[MLA_PFX_HDR_SIZE], mla_prefix_t *p) {
    if (hdr[0]!='M' || hdr[1]!='L' || hdr[2]!='A' || hdr[3]!=0) return 0;
    p->version        = hdr[4];
    p->cluster_shift  = hdr[5];
    p->log_rec_size   = hdr[6];
    p->flags          = hdr[7];
    p->file_size      = mla_get_u32(hdr + 8);
    p->container_kind = hdr[20];
    p->file_seq       = mla_get_u16(hdr + 21);
    p->keyframe_intv  = hdr[23];
    p->enc_caps       = hdr[24];
    p->data_base      = mla_get_u32(hdr + 25);
    p->region_end     = mla_get_u32(hdr + 29);
    return 1;
}

#endif /* NIC_MLA_FORMAT_H */
